    pub fn get_currency_id_from_code_and_network(&self, mut currencyCode: Value, mut networkCode: Value) -> Value {
        if is_equal(&networkCode, &Value::Null) {
            networkCode = self.default_network_code(currencyCode.clone()); // use default network code if not provided
        }
        let mut currency: Value = self.currency(currencyCode.clone());
        let mut id: Value = get_value(&currency, &Value::Str("id".to_string()));
        let mut idFromNetwork: Value = Value::Null;
        let mut networks: Value = self.safe_dict_k(currency.clone(), "networks", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        let mut networkInfo: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        });
        if is_equal(&networkCode, &Value::Null) {
            // network code is not provided and there is no default network code
            let mut network: Value = self.safe_dict(networks.clone(), currencyCode.clone(), &[]); // trying to find network that has the same code as currency
            if is_equal(&network, &Value::Null) {
                // use the first network in the networks list if there is no network code with the same code as currency
                let mut keys: Value = object_keys(&networks);
                let mut length: Value = get_array_length(&keys);
                if is_greater_than(&length, &Value::Int(0)) {
                    network = self.safe_value(networks.clone(), get_value(&keys, &Value::Int(0)), &[]);
                }
            }
            networkInfo = self.safe_dict_k(network.clone(), "info", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
            idFromNetwork = self.safe_string_k(networkInfo.clone(), "currency", &[]); // use currency name from network
        }  else {
            let mut providedOrDefaultNetwork: Value = self.safe_dict(networks.clone(), networkCode.clone(), &[]);
            if !is_equal(&providedOrDefaultNetwork, &Value::Null) {
                networkInfo = self.safe_dict_k(providedOrDefaultNetwork.clone(), "info", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
                idFromNetwork = self.safe_string_k(networkInfo.clone(), "currency", &[]); // use currency name from network
            }  else {
                id = add(&id, &add(&Value::Str("-".to_string()), &self.network_code_to_id(networkCode.clone(), &[currencyCode.clone()]))); // use concatenated currency id and network code if network is not found
            }
        }
        return ternary(is_true(&(!is_equal(&idFromNetwork, &Value::Null))), idFromNetwork.clone(), id.clone());

    Value::Null
}

